onOptionChange:
{{
storeValue("deptReady", false)   // 🔥 block department dropdown

.then(() =>
  storeValue("selectedDepartment", null)   // 🔥 reset department cleanly
)

.then(() =>
  storeValue("selectedPO", Select_PO.selectedOptionValue)
)

.then(() =>
  storeValue(
    "currentVersion",
    "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === "x" ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    })
  )
)

.then(() => GetPOH.run())
.then(() => GetAnswers.run())
.then(() => GetPODeliverables.run())
.then(() => GetPOGroupTests.run())
.then(() => GetPONRE.run())

// 🔥 LOAD SIGN-OFF DATA (CRITICAL FOR FILTERING)
.then(() => GetDepartmentSignOff.run())

// 🔥 BUILD ANSWER STATE
.then(() => {

  const existing = {};

  (GetAnswers.data || []).forEach(a => {
    existing[a.QuestionId] = {
      YesNo: a.YesNo,
      Answer: a.Answer,
      AnsweredBy: a.AnsweredBy,
      AnsweredDate: a.AnsweredDate,
      ResponsiblePerson: a.ResponsiblePerson,
      Action: a.Action,
      DueDate: a.DueDate
    };
  });

  return storeValue("answers", existing)
    .then(() =>
      storeValue(
        "originalAnswers",
        JSON.parse(JSON.stringify(existing))
      )
    );

})

// 🔥 FINAL STEP: UNLOCK DROPDOWN ONLY WHEN EVERYTHING IS READY
.then(() => storeValue("deptReady", true))

.catch((err) => {
  console.error("Select_PO failed:", err);
  showAlert("Failed to load PO data", "error");
  storeValue("deptReady", false);
})
}}
